UPDATE public.questions SET
  stimulus_text = 'The sentence "When the ship crashed, they had to rely on their knowledge of the sea to survive" is an example of the writer using a specific technique to make the passage more interesting and engaging.  The sentence is a good example of how a writer can use a technique known as *juxtaposition*, which is the placement of two things close together for contrasting effect. This technique can help to make the reader think about the passage in new ways. What is the most likely reason why the writer uses the word *juxtaposition* in this passage?',
  question_text = 'The writer likely uses the word "juxtaposition" to',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"explain how the writer uses this technique to make the passage more interesting.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"create a sense of contrast between the two things being juxtaposed.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"suggest that the writer is using a common literary technique.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"emphasize the importance of the writer’s message.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'Juxtaposition is a literary technique that places two things close together for contrasting effect. In this sentence, the writer is contrasting the idea of a ship crashing, which is a negative event, with the idea of relying on knowledge of the sea to survive, which is a positive event. This contrast helps to make the reader think about the passage in new ways. The passage states that "The sentence "When the ship crashed, they had to rely on their knowledge of the sea to survive" is an example of the wri…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: create a sense of contrast between the two things being juxtaposed.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
